import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.model.ContentTypes._
import akka.http.scaladsl.server.Directives._
import scala.concurrent.Future
import scala.xml.{Elem, NodeSeq, XML}
import akka.actor.ActorSystem
import akka.stream.ActorMaterializer

object ConfigParserService {
  implicit val system: ActorSystem = ActorSystem("config-parser-system")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  import system.dispatcher

  def parseXML(xmlString: String): Seq[(String, String)] = {
    val xml: Elem = XML.loadString(xmlString)
    (xml \\ "setting").map { settingNode =>
      val key = (settingNode \ "@key").text
      val value = settingNode.text
      key -> value
    }
  }

  val route =
    path("parse") {
      post {
        entity(as[String]) { xmlString =>
          val settings = parseXML(xmlString)
          complete(HttpEntity(`application/json`, settings.toJson.compactPrint))
        }
      }
    }

  def main(args: Array[String]): Unit = {
    val bindingFuture: Future[Http.ServerBinding] = Http().bindAndHandle(route, "localhost", 8080)
    println("Server online at http://localhost:8080/")
  }
}